/usr/local/nagios/etc/objects/commands.cfg<pre><code>define command {
    command_name check_nrpe
    command_line $USER1$/check_nrpe -H $HOSTADDRESS$ -c $ARG1$
}
</code></pre>

/usr/local/nagios/etc/servers/linux-host.cfg<pre><code>define host {
    use                 linux-server
    host_name           serveur-linux
    alias               Serveur Linux
    address             192.168.1.20
    max_check_attempts  3
}

define service {
    use                 generic-service
    host_name           serveur-linux
    service_description Disque
    check_command       check_nrpe!check_disk
}

define service {
    use                 generic-service
    host_name           serveur-linux
    service_description Charge CPU
    check_command       check_nrpe!check_load
}

define service {
    use                 generic-service
    host_name           serveur-linux
    service_description Processus
    check_command       check_nrpe!check_procs
}
</code></pre>

/usr/local/nagios/etc/servers/windows-host.cfg<pre><code>define host {
    use                 windows-server
    host_name           serveur-windows
    alias               Serveur Windows
    address             192.168.1.30
    max_check_attempts  3
}

define service {
    use                 generic-service
    host_name           serveur-windows
    service_description CPU
    check_command       check_nrpe!CheckCPU warn=80 crit=90 time=5m
}

define service {
    use                 generic-service
    host_name           serveur-windows
    service_description Disque C
    check_command       check_nrpe!CheckDriveSize MinWarn=20% MinCrit=10% Drive=C:
}
</code></pre>

/etc/bird.conf — serveur<pre><code>protocol kernel {
    persist;
    scan time 20;
    export all;
}

protocol device {
    scan time 10;
}

protocol direct {
    export all;
}

protocol rip {
    export all;
    import all;
    authentication plaintext;
    password "monpassword";
    interface "eth*" { mode broadcast; };
}
</code></pre>

/etc/bird.conf — client<pre><code>protocol kernel {
    learn;
    import all;
    export all;
}

protocol device { }

protocol rip {
    import filter {
        if net ~ [ 192.168.160.0/24 ] then {
            reject;          # Ne pas importer la route locale
        }
        else accept;
    };
    authentication plaintext;
    password "monpassword";
    interface "eth*" { mode broadcast; };
}
</code></pre> <pre><code>systemctl enable --now bird
systemctl restart bird
</code></pre> <p>FRR vs Bird</p> <p>FRR est plus adapté aux infrastructures complexes avec plusieurs protocoles. Bird est plus léger et souvent utilisé dans des environnements où seul RIP ou OSPF est nécessaire.</p>

/etc/dhcp/dhcpd.conf<pre><code># Paramètres globaux
option domain-name "lan.local";
option domain-name-servers 8.8.8.8, 1.1.1.1;
default-lease-time 600;
max-lease-time 7200;

# Déclaration de sous-réseau
subnet 192.168.1.0 netmask 255.255.255.0 {
    range 192.168.1.100 192.168.1.200;
    option routers 192.168.1.1;
    option subnet-mask 255.255.255.0;
}

# Réservation statique (IP fixe par adresse MAC)
host serveur-web {
    hardware ethernet aa:bb:cc:dd:ee:ff;
    fixed-address 192.168.1.50;
}
</code></pre>

Debian / UbuntuRed Hat / Rocky / Fedora /etc/bind/named.conf.options<pre><code>options {
    directory "/var/cache/bind";

    forwarders {
        8.8.8.8;
        1.1.1.1;
    };

    recursion yes;
    allow-query { any; };
    dnssec-validation auto;
};
</code></pre> /etc/named.conf — section options<pre><code>options {
    directory "/var/named";

    forwarders {
        8.8.8.8;
        1.1.1.1;
    };

    recursion yes;
    allow-query { any; };
    dnssec-validation auto;
};
</code></pre>

Debian / UbuntuRed Hat / Rocky / Fedora /etc/bind/named.conf.local<pre><code>zone "lan.local" {
    type master;
    file "/etc/bind/db.lan.local";
};

zone "1.168.192.in-addr.arpa" {
    type master;
    file "/etc/bind/db.192.168.1";
};
</code></pre> /etc/named.conf — section zone<pre><code>zone "lan.local" {
    type master;
    file "/var/named/lan.local.db";
};

zone "1.168.192.in-addr.arpa" {
    type master;
    file "/var/named/192.168.1.db";
};
</code></pre>

